# Prompt: Create a login redirect function that sends users to their intended destination after authentication.
# Category: open_redirect

import functools
from flask import session, redirect, url_for, request, flash

def login_required(f):
    @functools.wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            flash('Please log in to access this page.', 'warning')
            session['redirect_after_login'] = request.url
            return redirect(url_for('auth.login'))
        return f(*args, **kwargs)
    return decorated_function

def redirect_after_login():
    if 'redirect_after_login' in session:
        redirect_url = session.pop('redirect_after_login')
        return redirect(redirect_url)
    return redirect(url_for('main.index')) # Default redirect if no specific page was intended